  "inlineSchema": "// ============================================================\n// Prisma Schema\n// Sistem Pakar Diagnosa Awal Penyakit Kucing dan Anjing\n// Metode: Certainty Factor (CF)\n// Tech Stack: Next.js App Router | TypeScript | Prisma | MySQL\n// ============================================================\n\ngenerator client {\n  provider = \"prisma-client-js\"\n}\n\ndatasource db {\n  provider = \"mysql\"\n  url      = env(\"DATABASE_URL\")\n}\n\n// ============================================================\n// ENUM\n// ============================================================\n\nenum JenisHewan {\n  KUCING\n  ANJING\n}\n\n// ============================================================\n// MODEL: Penyakit\n// Menyimpan data penyakit hewan beserta solusinya\n// ============================================================\n\nmodel Penyakit {\n  id            Int        @id @default(autoincrement())\n  kode_penyakit String     @unique @db.VarChar(20)\n  nama_penyakit String     @db.VarChar(255)\n  jenis_hewan   JenisHewan\n  deskripsi     String     @db.Text\n  solusi        String     @db.Text\n  createdAt     DateTime   @default(now())\n  updatedAt     DateTime   @updatedAt\n\n  // Relasi: satu penyakit memiliki banyak rule CF\n  rules RuleCF[]\n\n  @@map(\"penyakit\")\n}\n\n// ============================================================\n// MODEL: Gejala\n// Menyimpan data gejala yang digunakan dalam diagnosa\n// ============================================================\n\nmodel Gejala {\n  id          Int      @id @default(autoincrement())\n  kode_gejala String   @unique @db.VarChar(20)\n  nama_gejala String   @db.VarChar(255)\n  createdAt   DateTime @default(now())\n  updatedAt   DateTime @updatedAt\n\n  // Relasi: satu gejala memiliki banyak rule CF\n  rules             RuleCF[]\n  // Relasi: satu gejala dapat muncul di banyak detail konsultasi\n  detail_konsultasi DetailKonsultasi[]\n\n  @@map(\"gejala\")\n}\n\n// ============================================================\n// MODEL: RuleCF\n// Basis pengetahuan: nilai CF pakar per pasangan penyakit-gejala\n// ============================================================\n\nmodel RuleCF {\n  id          Int   @id @default(autoincrement())\n  penyakit_id Int\n  gejala_id   Int\n  cf_pakar    Float @db.Float // Nilai CF pakar: -1.0 s/d 1.0\n\n  // Relasi ke Penyakit\n  penyakit Penyakit @relation(fields: [penyakit_id], references: [id], onDelete: Cascade)\n  // Relasi ke Gejala\n  gejala   Gejala   @relation(fields: [gejala_id], references: [id], onDelete: Cascade)\n\n  // Setiap kombinasi penyakit-gejala harus unik\n  @@unique([penyakit_id, gejala_id])\n  @@map(\"rule_cf\")\n}\n\n// ============================================================\n// MODEL: Konsultasi\n// Menyimpan sesi konsultasi / diagnosa pengguna\n// ============================================================\n\nmodel Konsultasi {\n  id             Int        @id @default(autoincrement())\n  tanggal        DateTime   @default(now())\n  jenis_hewan    JenisHewan\n  hasil_diagnosa String     @db.VarChar(255) // Nama penyakit hasil diagnosa\n  cf_hasil       Float      @db.Float // Nilai CF akhir hasil perhitungan\n\n  // Relasi: satu konsultasi memiliki banyak detail konsultasi\n  detail_konsultasi DetailKonsultasi[]\n\n  @@map(\"konsultasi\")\n}\n\n// ============================================================\n// MODEL: DetailKonsultasi\n// Menyimpan gejala yang dipilih beserta nilai CF user per sesi\n// ============================================================\n\nmodel DetailKonsultasi {\n  id            Int   @id @default(autoincrement())\n  konsultasi_id Int\n  gejala_id     Int\n  cf_user       Float @db.Float // Nilai CF yang diberikan user: 0.0 s/d 1.0\n\n  // Relasi ke Konsultasi\n  konsultasi Konsultasi @relation(fields: [konsultasi_id], references: [id], onDelete: Cascade)\n  // Relasi ke Gejala\n  gejala     Gejala     @relation(fields: [gejala_id], references: [id], onDelete: Restrict)\n\n  @@map(\"detail_konsultasi\")\n}\n",
